import sys


def main():
    raw = sys.argv[1] if len(sys.argv) > 1 else ""
    raw = raw.strip()
    if not raw:
        print()
        return

    numbers = set()
    for token in raw.split(","):
        token = token.strip()
        if not token:
            continue
        if "-" in token:
            a, b = token.split("-", 1)
            a = int(a.strip())
            b = int(b.strip())
            numbers.update(range(a, b + 1))
        else:
            numbers.add(int(token))

    print(" ".join(str(n) for n in sorted(numbers)))


if __name__ == "__main__":
    main()

